const companies = $input.all().map(i => i.json);
const now = new Date();
const currentHour = now.getHours();
const currentDay = now.getDay();
const currentDate = now.getDate();

const dueCompanies = companies.filter(c => {
  const rs = c.report_settings;
  if (!rs || !rs.enabled) return false;
  const reportHour = parseInt((rs.time || '09:00').split(':')[0]);
  if (reportHour !== currentHour) return false;
  if (rs.frequency === 'weekly' && rs.day_of_week !== currentDay) return false;
  if (rs.frequency === 'monthly' && currentDate !== 1) return false;
  return true;
});

return dueCompanies.map(c => ({ json: c }));

const company = $input.first().json;
const rs = company.report_settings;
const now = new Date();
let startDate, endDate;

if (rs.frequency === 'weekly') {
  endDate = new Date(now);
  startDate = new Date(now);
  startDate.setDate(startDate.getDate() - 7);
} else {
  endDate = new Date(now.getFullYear(), now.getMonth(), 0);
  startDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
}

const format = d => d.toISOString().split('T')[0];
return [{ json: { company_id: company.id, company_name: company.name, start_date: format(startDate), end_date: format(endDate), modules: rs.modules || [], channels: rs.channels || ['whatsapp'], manager_phone: company.manager_phone } }];
